"use client";

import { RotateCw } from "lucide-react";
import type { ReactNode } from "react";
import { useCallback, useEffect, useState } from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export const ComponentPreviewClient = ({
  children,
  className,
}: {
  children: ReactNode;
  className?: string;
}) => {
  const [previewKey, setPreviewKey] = useState(0);

  const handleRestart = useCallback(() => {
    setPreviewKey((prev) => prev + 1);
  }, []);

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === "r" || event.key === "R") {
        handleRestart();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [handleRestart]);

  return (
    <div
      className={cn(
        "group relative flex min-h-[350px] items-center justify-center overflow-hidden rounded-2xl border border-border/60 bg-muted/30 p-12 backdrop-blur-sm",
        className
      )}
    >
      <div className="pointer-events-none absolute inset-0 [background-image:radial-gradient(circle,currentColor_1px,transparent_1px)] [background-size:20px_20px] opacity-[0.06]" />
      <div className="absolute right-4 top-4 z-50">
        <Button
          variant="outline"
          size="icon"
          onClick={handleRestart}
          className="h-8 w-8 active:scale-95 duration-300 ease-out transition-[scale,background-color,opacity] group/restart-button"
          aria-label="Restart demo"
        >
          <RotateCw className="h-4 w-4 group-hover/restart-button:rotate-45 duration-300 ease-out transition-transform" />
        </Button>
      </div>
      <div
        key={previewKey}
        className="relative z-10 flex w-full items-center justify-center isolate"
      >
        {children}
      </div>
    </div>
  );
};

"use client";

import type { Transition, UseInViewOptions } from "motion/react";
import { motion, useInView } from "motion/react";
import type { ElementType } from "react";
import {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from "react";

import { cn } from "@/lib/utils";

type HighlightDirection = "ltr" | "rtl" | "ttb" | "btt";

type TextHighlighterProps = {
  // The text content to be highlighted
  children: React.ReactNode;
  // HTML element to render as (default: "span")
  as?: ElementType;
  // How to trigger the animation (default: "inView")
  triggerType?: "hover" | "ref" | "inView" | "auto";
  // Animation transition configuration
  transition?: Transition;
  // Options for useInView hook when triggerType is "inView"
  useInViewOptions?: UseInViewOptions;
  // Class name for the container element
  className?: string;
  // Highlight color (CSS color string)
  highlightColor?: string;
  // Direction of the highlight animation (default: "ltr")
  direction?: HighlightDirection;
} & React.HTMLAttributes<HTMLElement>;

export interface TextHighlighterRef {
  // Trigger the highlight animation
  animate: (direction?: HighlightDirection) => void;
  // Reset the highlight animation
  reset: () => void;
}

export const TextHighlighter = forwardRef<
  TextHighlighterRef,
  TextHighlighterProps
>(
  (
    {
      children,
      as = "span",
      triggerType = "inView",
      transition = { bounce: 0, delay: 0, duration: 1, type: "spring" },
      useInViewOptions = {
        amount: 0.1,
        initial: false,
        once: true,
      },
      className,
      highlightColor = "hsl(25, 90%, 80%)",
      direction = "ltr",
      ...props
    },
    ref
  ) => {
    const componentRef = useRef<HTMLDivElement>(null);
    const [isAnimating, setIsAnimating] = useState(false);
    const [isHovered, setIsHovered] = useState(false);
    const [currentDirection, setCurrentDirection] =
      useState<HighlightDirection>(direction);

    // this allows us to change the direction whenever the direction prop changes
    useEffect(() => {
      setCurrentDirection(direction);
    }, [direction]);

    const isInView =
      triggerType === "inView"
        ? useInView(componentRef, useInViewOptions)
        : false;

    useImperativeHandle(ref, () => ({
      animate: (animationDirection?: HighlightDirection) => {
        if (animationDirection) {
          setCurrentDirection(animationDirection);
        }
        setIsAnimating(true);
      },
      reset: () => setIsAnimating(false),
    }));

    let shouldAnimate = false;
    if (triggerType === "hover") {
      shouldAnimate = isHovered;
    } else if (triggerType === "inView") {
      shouldAnimate = isInView;
    } else if (triggerType === "ref") {
      shouldAnimate = isAnimating;
    } else if (triggerType === "auto") {
      shouldAnimate = true;
    }

    const ElementTag = as || "span";

    // Get background size based on direction
    const getBackgroundSize = (animated: boolean) => {
      switch (currentDirection) {
        case "ltr": {
          return animated ? "100% 100%" : "0% 100%";
        }
        case "rtl": {
          return animated ? "100% 100%" : "0% 100%";
        }
        case "ttb": {
          return animated ? "100% 100%" : "100% 0%";
        }
        case "btt": {
          return animated ? "100% 100%" : "100% 0%";
        }
        default: {
          return animated ? "100% 100%" : "0% 100%";
        }
      }
    };

    // Get background position based on direction
    const getBackgroundPosition = () => {
      switch (currentDirection) {
        case "ltr": {
          return "0% 0%";
        }
        case "rtl": {
          return "100% 0%";
        }
        case "ttb": {
          return "0% 0%";
        }
        case "btt": {
          return "0% 100%";
        }
        default: {
          return "0% 0%";
        }
      }
    };

    const animatedSize = getBackgroundSize(shouldAnimate);
    const initialSize = getBackgroundSize(false);
    const backgroundPosition = getBackgroundPosition();

    const highlightStyle = {
      WebkitBoxDecorationBreak: "clone",
      backgroundImage: `linear-gradient(${highlightColor}, ${highlightColor})`,
      backgroundPosition,
      backgroundRepeat: "no-repeat",
      backgroundSize: animatedSize,
      boxDecorationBreak: "clone",
    } as React.CSSProperties;

    return (
      <ElementTag
        ref={componentRef}
        onMouseEnter={() => triggerType === "hover" && setIsHovered(true)}
        onMouseLeave={() => triggerType === "hover" && setIsHovered(false)}
        {...props}
      >
        <motion.span
          className={cn("inline", className)}
          style={highlightStyle}
          animate={{
            backgroundSize: animatedSize,
          }}
          initial={{
            backgroundSize: initialSize,
          }}
          transition={transition}
        >
          {children}
        </motion.span>
      </ElementTag>
    );
  }
);

TextHighlighter.displayName = "TextHighlighter";

export default TextHighlighter;

